	background: var(--color-background-dark);

	.logo-header {
		.logo-icon {
			height: 80px;

			@media (max-width: 768px) {
				height: 60px;
			}
		}
	}

	.error-container {
		max-width: 800px;
		width: 100%;
		padding: 48px 32px;
		background: var(--color-main-background);
		border-radius: var(--border-radius-large);
		box-shadow: 0 2px 16px rgba(0, 0, 0, 0.1);

		:deep(.empty-content__action) {
			min-width: 500px;

			@media (max-width: 768px) {
				min-width: 100%;
			}
		}

		.error-messages {
